// 1. 引入对应模块
import Vue from 'vue'
import VueRouter  from 'vue-router'

const login = ()=> import('./../pages/AdminLogin/login'); // 登录
const register = ()=> import('./../pages/AdminLogin/register'); // 注册
const Admin = ()=> import('./../pages/Admin/Admin'); // 首页

// 普通用户
const enquiry = ()=> import('./../pages/Admin/Children/enquiry'); // 明细查询
const recharge = ()=> import('./../pages/Admin/Children/recharge'); // 存款
const withdrawals = ()=> import('./../pages/Admin/Children/withdrawals'); // 取款
const transfer = ()=> import('./../pages/Admin/Children/transfer'); // 转账
const changePassword = ()=> import('./../pages/Admin/Children/changePassword'); // 修改密码
const userCharts = ()=> import('./../pages/Admin/Children/userCharts'); // 数据统计

// 管理员
const adminRecharge = ()=> import('./../pages/Admin/Children/adminRecharge'); // 加钞/取钞
const atmAccount = ()=> import('./../pages/Admin/Children/atmAccount'); // ATM钞票记录
const adminTrad = ()=> import('./../pages/Admin/Children/adminTrad'); // 明细查询
const adminUser = ()=> import('./../pages/Admin/Children/adminUser'); // 用户查询
const adminCharts = ()=> import('./../pages/Admin/Children/adminCharts'); // 数据统计


// 2. 声明使用
Vue.use(VueRouter);

// 3. 输出路由对象
export default  new VueRouter({
  // 3.1 配置一级路由
  routes: [
	{
	  path: '/login',
	  component: login
  },
	{
	  path: '/register',
	  component: register
  },
  {
	  path: '/admin',
    component: Admin,
    children: [
      {path: 'enquiry', component: enquiry},
      {path: 'recharge', component: recharge},
      {path: 'withdrawals', component: withdrawals},
      {path: 'transfer', component: transfer},
      {path: 'changePassword', component: changePassword},
      {path: 'userCharts', component: userCharts},

      {path: 'adminRecharge', component: adminRecharge},
      {path: 'atmAccount', component: atmAccount},
      {path: 'adminTrad', component: adminTrad},
      {path: 'adminUser', component: adminUser},
      {path: 'adminCharts', component: adminCharts},

    ],
  },
	{
	  path: '/',
	  redirect: '/login'
	},
  ]
});



